146	func Attempt(ctx context.Context, store Store, beadID string, opts AttemptOpts) (Outcome, error) {
147		if opts.Executor == nil {
148			return Outcome{}, fmt.Errorf("try attempt: executor is required")
149		}
150		rateCfg := resolveRateLimitRetryConfig(opts)
151		var (
152			report Report
153			err    error
154		)
155		for retryCount, elapsed := 0, time.Duration(0); ; {
156			report, err = opts.Executor.Execute(ctx, beadID)
157			if err != nil {
158				report = Report{
159					BeadID: beadID,
160					Status: StatusExecutionFailed,
161					Detail: err.Error(),
162					Error:  err.Error(),
163				}
164			}
165			if report.BeadID == "" {
166				report.BeadID = beadID
167			}
168			if report.Status == "" {
169				report.Status = StatusExecutionFailed
170			}
171	
172			rateLimited := IsRateLimitReport(&report)
173			effectiveBudget := rateCfg.Budget
174			if opts.RateLimitBudget == 0 && report.RateLimitBudget != 0 {
175				effectiveBudget = report.RateLimitBudget
176			}
177			decision, retryAfter := evaluateRateLimitAttempt(report, rateCfg, retryCount+1, elapsed, effectiveBudget)
178			if !decision.ShouldRetry {
179				if decision.Reason != "" {
180					report.Error = decision.Reason
181				}
182				if rateLimited && decision.Reason != "" && rateCfg.OnRetry != nil {
183					rateCfg.OnRetry(ctx, RateLimitRetryInfo{
184						Attempt:    retryCount + 1,
185						Source:     decision.Source,
186						Report:     &report,
187						Elapsed:    elapsed,
188						RetryAfter: retryAfter,
189						OverBudget: true,
190					})
191				}
192				break
193			}
194	
195			retryCount++
196			info := RateLimitRetryInfo{
197				Attempt:    retryCount,
198				Wait:       decision.Wait,
199				Source:     decision.Source,
200				Report:     &report,
201				Elapsed:    elapsed,
202				RetryAfter: retryAfter,
203			}
204			if rateCfg.OnRetry != nil {
205				rateCfg.OnRetry(ctx, info)
206			}
207			if err := rateCfg.Sleep(ctx, decision.Wait); err != nil {
208				return Outcome{}, err
209			}
210			elapsed += decision.Wait
211		}
212	
213		if ShouldAttemptConflictRecovery(report, opts.ProjectRoot) {
214			if opts.Store == nil {
215				opts.Store = store
216			}
217			return ConflictRecoveryOutcome(ctx, ConflictRecoveryInput{
218				Bead:             opts.Bead,
219				Report:           report,
220				ProjectRoot:      opts.ProjectRoot,
221				AutoRecover:      opts.AutoRecover,
222				ConflictResolver: opts.ConflictResolver,
223				Store:            opts.Store,
224				Assignee:         opts.Assignee,
225				Now:              opts.Now,
226				Cooldown:         opts.Cooldown,
227			}), err
228		}
229	
230		if report.Status == StatusNoChanges {
231			if opts.Store == nil {
232				opts.Store = store
233			}
234			if opts.Store == nil {
235				return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: fmt.Errorf("try attempt: no_changes store is required")}, nil
236			}
237			noChangesCount, countErr := opts.Store.IncrNoChangesCount(beadID)
238			if countErr != nil {
239				return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: countErr}, nil
240			}
241			noChangesOut, adjudicatedReport, adjErr := adjudicateNoChangesContract(ctx, beadID, report, opts.ProjectRoot, noChangesCount, opts.SatisfactionChecker, opts.VerificationRunner)
242			if adjErr != nil {
243				return Outcome{Report: report, StoreErrOp: "adjudicateNoChanges", StoreErr: adjErr}, nil
244			}
245			return Outcome{
246				Report:      adjudicatedReport,
247				Disposition: OutcomeReported,
248				NoChanges:   &noChangesOut,
249			}, nil
250		}
251	
252		if report.Status == StatusDeclinedNeedsDecomposition {
253			parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
254			report.RetryAfter = parkUntil.Format(time.RFC3339)
255			event := buildDecompositionParkingEvent(report)
256			return Outcome{
257				Report:      report,
258				Disposition: OutcomePark,
259				Parking: &ParkingOutcome{
260					Unclaim:              true,
261					RetryAfter:           parkUntil,
262					RunPostAttemptTriage: true,
263					Event:                event,
264				},
265			}, nil
266		}
267	
268		if report.Status == StatusPushFailed {
269			parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
270			report.RetryAfter = parkUntil.Format(time.RFC3339)
271			return Outcome{
272				Report:      report,
273				Disposition: OutcomePark,
274				Parking: &ParkingOutcome{
275					Unclaim:              true,
276					RetryAfter:           parkUntil,
277					RunPostAttemptTriage: true,
278				},
279			}, nil
280		}
281	
282		if report.Status == StatusPushConflict {
283			parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
284			report.RetryAfter = parkUntil.Format(time.RFC3339)
285			event := buildPushConflictParkingEvent(report)
286			return Outcome{
287				Report:      report,
288				Disposition: OutcomePark,
289				Parking: &ParkingOutcome{
290					Unclaim:              true,
291					RetryAfter:           parkUntil,
292					RunPostAttemptTriage: true,
293					Event:                event,
294				},
295			}, nil
296		}
297	
298		return Outcome{Report: report, Disposition: OutcomeReported}, err
299	}
