109	// SubmitWithPreMergeChecks is the canonical land-back step for the execute-bead
110	// loop. It runs the project's .ddx/checks/*.yaml gate against the worker's
111	// (baseRev, resultRev) before forwarding to submit. On Blocked, it preserves
112	// the worker's result under refs/ddx/iterations/, records checks-blocked
113	// events on the bead, and returns the synthesised LandResult{Status:"preserved"}
114	// without ever calling submit. On pass, honoured checks-bypass annotations are
115	// recorded as checks-bypass events and submit runs normally.
116	//
117	// submit is the project's land coordinator entry point (typically
118	// LocalLandCoordinator.Submit or the server-side coordinator submit).
119	//
120	// The implementation lives in checks_premerge.go alongside its supporting
121	// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
122	// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
123	// loop's land-back call site is one obvious helper rather than three nested
124	// ones, and so callers wiring the gate do not need to import the helper layer
125	// directly.
126	func SubmitWithPreMergeChecks(
127		ctx context.Context,
128		projectRoot string,
129		b *bead.Bead,
130		res *ExecuteBeadResult,
131		submit func(LandRequest) (*LandResult, error),
132		eventStore BeadEventAppender,
133		actor, source string,
134		now func() time.Time,
135	) (*LandResult, *PreMergeChecksOutcome, error) {
136		if now == nil {
137			now = time.Now
138		}
139		if submit == nil {
140			return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
141		}
142		evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
143		outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
144		if err != nil {
145			// Treat checks_bypass / loader errors as a hard preserve: the worker
146			// did its job; the operator misconfigured the gate. Better to park
147			// the result under an iteration ref than to silently land it.
148			ref := PreserveRef(res.BeadID, res.BaseRev)
149			if upErr := (&RealOrchestratorGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
150				return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
151			}
152			return &LandResult{
153				Status:      "preserved",
154				PreserveRef: ref,
155				Reason:      "pre-merge checks setup error: " + err.Error(),
156			}, nil, nil
157		}
158		if outcome.Blocked {
159			land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealOrchestratorGitOps{})
160			if perr != nil {
161				return nil, outcome, perr
162			}
163			if eventStore != nil {
164				_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
165			}
166			return land, outcome, nil
167		}
168		if eventStore != nil && len(outcome.Bypassed) > 0 {
169			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
170		}
171		land, sErr := submit(BuildLandRequestFromResult(projectRoot, res))
172		return land, outcome, sErr
173	}
