176	// the attempt outcome has been finalized but before any cooldown decision is
177	// applied. Hook failures are fail-open: the report is returned unchanged and
178	// legacy cooldown behavior remains in force.
179	func (w *ExecuteBeadWorker) runPostAttemptTriage(ctx context.Context, candidate bead.Bead, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime, assignee string, now func() time.Time) ExecuteBeadReport {
180		hook := runtime.PostAttemptTriageHook
181		if hook == nil {
182			return report
183		}
184		triage, err := hook(ctx, candidate.ID, report)
185		if err != nil {
186			if runtime.Log != nil {
187				_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage error (%s %s): %v (continuing)\n", candidate.ID, report.Status, err)
188			}
189			return report
190		}
191		if strings.TrimSpace(triage.Classification) == "" {
192			return report
193		}
194		report.OutcomeReason = triage.Classification
195		recordPostAttemptTriageEvent(w.Store, candidate.ID, report, triage, assignee, now().UTC())
196		return report
197	}
